$sec = ConvertTo-SecureString '125412' -AsPlainText -Force
$cred = New-Object PSCredential ('portkkm\cherkasov.n', $sec)
$script = {
  $vpn = '10.220.220.0/24'
  # ICMP echo allow from VPN
  $name = 'Allow ICMPv4 from Port-Mol VPN'
  if (-not (Get-NetFirewallRule -DisplayName $name -EA SilentlyContinue)) {
    New-NetFirewallRule -DisplayName $name -Direction Inbound -Protocol ICMPv4 -ICMPType 8 -RemoteAddress $vpn -Action Allow -Profile Any -Enabled True | Out-Null
  } else {
    Set-NetFirewallRule -DisplayName $name -RemoteAddress $vpn -Action Allow -Enabled True -Profile Any
  }
  # also ensure File/Printer Sharing echo is on for Domain+Private+Public
  Get-NetFirewallRule -DisplayGroup 'File and Printer Sharing' -EA SilentlyContinue |
    Where-Object { $_.DisplayName -match 'ICMPv4|эхо-запрос' -and $_.Direction -eq 'Inbound' } |
    ForEach-Object { Enable-NetFirewallRule -Name $_.Name -EA SilentlyContinue; Set-NetFirewallRule -Name $_.Name -Profile Any -EA SilentlyContinue }
  # RDP from VPN (useful even if ping still filtered by AV)
  $rdp = 'Allow RDP from Port-Mol VPN'
  if (-not (Get-NetFirewallRule -DisplayName $rdp -EA SilentlyContinue)) {
    New-NetFirewallRule -DisplayName $rdp -Direction Inbound -Protocol TCP -LocalPort 3389 -RemoteAddress $vpn -Action Allow -Profile Any -Enabled True | Out-Null
  }
  Get-NetFirewallRule -DisplayName $name,$rdp | Select DisplayName,Enabled,Direction,Action | Format-Table -AutoSize | Out-String
  'OK ' + $env:COMPUTERNAME
}
